    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Easy',
    4,
    'Beginner Yoga - 4w 4x/wk',
    'yoga',
    4,
    60,
    ARRAY['Improve flexibility', 'Enhance body awareness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Beginner Yoga'
ON CONFLICT DO NOTHING;

